#include <bits/stdc++.h>
using namespace std;
struct def{
    string s;
    int p,v;
}a[1001];
bool cmp(def c, def b){
    if(c.v!=b.v){
        return c.v<b.v;
    }
    else if(c.p!=b.p){
        return c.p<b.p;
    }
    return c.s<b.s;
    }
bool cmp1(string b,string c){
	return b<c;
	}
int main(){
    int n,m;
    cin>>m>>n;
    for(int i=0;i<n;i++){
        cin>>a[i].s>>a[i].p>>a[i].v;
    }
    sort(a,a+n,cmp);
    string d[n];
    int t=0;
    for(int i=0;i<n;i++){
		if(m-a[i].p>=0){
			m-=a[i].p;
			d[t]=a[i].s;
			t++;
		}
	}
	sort(d,d+t,cmp1);
	for(int i=0;i<t;i++){
		cout<<d[i]<<endl;
	}
    return 0;
}
